import React from 'react'
import TicketCard from './TicketCard'
import { useDraggable, useDroppable } from '@dnd-kit/react';

function StatusColumn({ title, content }) {
    return <div className='border rounded-md border-gray-600 min-h-full bg-gray-300 p-4'>
        <div className='ahqt ahri ahrt ahsb ahsp ahsv ahtd ahtf ahtj ahud ahuk'>
            {title}
        </div>
        <div className='flex flex-col gap-y-4'>
            {content}
        </div>
    </div>
}

function groupBy(arr, key) {
    const dict = new Map()
    arr.forEach((item) => {
        dict.set(item[key], [...(dict.get(item[key]) || []), item])
    })
    return dict
}
function DroppableTickets({ columnTickets }) {
    columnTickets.map((tkt) => {
        return <TicketCard id={tkt.id} title={tkt.title} storyPoints={tkt.storyPoints} profilePicUrl={tkt.assignee.avatar} type={'STORY'} />
    })
}
export default function StatusColumns({ cards }) {
    const columns = groupBy(cards, 'ticketStatus')
    const titleComponent = (columnName) => <span>{columnName}</span>
    const contentComponent = (columnTickets) => columnTickets.map((tkt) => {
        const { ref } = useDroppable({ id: tkt.id })
        return <TicketCard ref={ref} id={tkt.id} title={tkt.title} storyPoints={tkt.storyPoints} profilePicUrl={tkt.assignee.avatar} type={'STORY'} />
    })

    return <div className='min-w-full flex flex-row gap-x-8 justify-center'>{columns.keys().map((columnName) => <StatusColumn key={columns.get(columnName).id} title={titleComponent(columnName)} content={contentComponent(columns.get(columnName))} />)}</div>
}
